SELECT COUNT(*) AS total_wells
FROM wells
WHERE initial_condition = 'Initial condition B';

SELECT cm.measurement_date, COUNT(DISTINCT cm.well_id) AS unique_wells_count
FROM community_metrics AS cm
GROUP BY cm.measurement_date;

SELECT well_id, transfer_id, AVG(richness) AS average_richness, AVG(biomass) AS average_biomass
FROM community_metrics
GROUP BY well_id, transfer_id;

SELECT AVG(initial_biomass) AS average_biomass, AVG(initial_richness) AS average_richness, AVG(initial_phenotype) AS average_phenotype
FROM wells
WHERE exp_id = '0';

SELECT u.user_name, u.email
FROM users u
INNER JOIN access_logs a ON u.user_id = a.user_id;

SELECT w.well_name, ic.condition_name 
FROM wells w 
JOIN initial_conditions ic ON w.initial_condition = ic.condition_id;
